void luFactorize(std::vector<COOElement> const& A, std::vector<double> &L, std::vector<double> &U, size_t N) {
   std::vector<double> fullA(N * N, 0.0);
   #pragma omp parallel for
   for (size_t idx = 0; idx < A.size(); ++idx) {
      const COOElement& elem = A[idx];
      fullA[elem.row * N + elem.column] = elem.value;
   }
   for (size_t i = 0; i < N; ++i) {
      for (size_t j = 0; j < N; ++j) {
         if (j >= i) {
            double u_val = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
               u_val -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = u_val;
         }
         if (i > j) {
            double l_val = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
               l_val -= L[i * N + k] * U[k * N + j];
            }
            l_val /= U[j * N + j];
            L[i * N + j] = l_val;
         }
      }
      L[i * N + i] = 1.0;
   }
}
